#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,a[10001];
    cin>>n;
    for(int i=0;i<n;i++){
        cin>>a[i];
        if(a[i]%2==1)cout<<a[i]<<' ';
    }
    cout<<endl;
    for(int i=0;i<n;i++){
        if(a[i]%2==0)cout<<a[i]<<' ';
    }
    return 0;
}
